customCss:
/* MF-QA-FIX-v1 */
.mfp.mfp-event-registration-rsvp{--mf-primary:var(--mf-preset-primary, #f59e0b);--mf-accent:var(--mf-preset-primary, #f59e0b);--mf-primary-hover:var(--mf-preset-primary, #d97706);--mf-primary-light:#fef3e0;--primary:var(--mf-preset-primary, #f59e0b);}
.mfp.mfp-event-registration-rsvp .mfp-header h1,.mfp.mfp-event-registration-rsvp .mfp-header .mfp-form-title,.mfp.mfp-event-registration-rsvp .mfp-header .mfp-eyebrow,.mfp.mfp-event-registration-rsvp .mfp-header .mfp-form-subtitle{color:#fff!important;}
/* END-MF-QA-FIX */
/* ============================================================
   MegaForm Premium Template — Event Registration & RSVP
   Scope: .mfp.mfp-event-registration-rsvp
   Design profile: Dark editorial, amber accent, sidebar stepper
   All colours use --mf-* variables; hard-coded values are
   fallbacks only.
   ============================================================ */

/* ---------- Reset ---------- */
.mfp.mfp-event-registration-rsvp *,
.mfp.mfp-event-registration-rsvp *::before,
.mfp.mfp-event-registration-rsvp *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

/* ---------- Root wrapper ---------- */
.mfp.mfp-event-registration-rsvp {
  font-family: inherit;
  color: var(--mf-text, #f1f0ed);
  background: var(--mf-bg, var(--mf-preset-bg, #0f0f13));
  border-radius: var(--mf-radius, 16px);
  max-width: 1040px;
  width: 100%;
  margin: 0 auto;
  overflow: hidden;
  box-shadow: var(--mf-shadow, 0 24px 80px rgba(0,0,0,0.55));
}

/* ---------- Layout: sidebar + main ---------- */
.mfp.mfp-event-registration-rsvp .mfp-layout {
  display: flex;
  min-height: 600px;
}

/* ============================================================
   SIDEBAR
   ============================================================ */
.mfp.mfp-event-registration-rsvp .mfp-sidebar {
  width: 280px;
  flex-shrink: 0;
  background: var(--mf-surface, var(--mf-preset-surface, #18181f));
  border-right: 1px solid var(--mf-border, color-mix(in srgb, var(--mf-preset-text, #ffffff) 8%, transparent));
  display: flex;
  flex-direction: column;
}

.mfp.mfp-event-registration-rsvp .mfp-sidebar-inner {
  display: flex;
  flex-direction: column;
  gap: 32px;
  padding: 36px 28px 32px;
  flex: 1;
}

/* Brand mark */
.mfp.mfp-event-registration-rsvp .mfp-brand {
  display: flex;
  align-items: center;
  gap: 8px;
}
.mfp.mfp-event-registration-rsvp .mfp-brand-dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background: var(--mf-accent, var(--mf-preset-primary, #f59e0b));
  flex-shrink: 0;
}
.mfp.mfp-event-registration-rsvp .mfp-brand-label {
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--mf-muted, color-mix(in srgb, var(--mf-preset-text, #f1f0ed) 45%, transparent));
}

/* Sidebar heading */
.mfp.mfp-event-registration-rsvp .mfp-form-title {
  font-size: clamp(20px, 2.4vw, 26px);
  font-weight: 800;
  line-height: 1.15;
  letter-spacing: -0.02em;
  color: var(--mf-text, #f1f0ed);
  margin-bottom: 10px;
}
.mfp.mfp-event-registration-rsvp .mfp-form-subtitle {
  font-size: 13px;
  line-height: 1.6;
  color: var(--mf-muted, color-mix(in srgb, var(--mf-preset-text, #f1f0ed) 50%, transparent));
}

/* ===== Vertical Stepper ===== */
.mfp.mfp-event-registration-rsvp .mfp-stepper {
  flex: 1;
}
.mfp.mfp-event-registration-rsvp .mfp-stepper-list {
  list-style: none;
  display: flex;
  flex-direction: column;
  gap: 0;
  position: relative;
}
.mfp.mfp-event-registration-rsvp .mfp-stepper-item {
  display: flex;
  align-items: flex-start;
  gap: 14px;
  padding: 14px 0;
  position: relative;
  cursor: default;
}

/* Vertical connector line */
.mfp.mfp-event-registration-rsvp .mfp-step-track {
  display: none;
}
.mfp.mfp-event-registration-rsvp .mfp-stepper-item:not(:last-child)::after {
  content: '';
  position: absolute;
  left: 15px;
  top: 38px;
  bottom: -10px;
  width: 1px;
  background: var(--mf-border, color-mix(in srgb, var(--mf-preset-text, #ffffff) 10%, transparent));
}

/* Step number badge */
.mfp.mfp-event-registration-rsvp .mfp-step-indicator {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: transparent;
  border: 1px solid var(--mf-border, color-mix(in srgb, var(--mf-preset-text, #ffffff) 15%, transparent));
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.04em;
  color: var(--mf-muted, color-mix(in srgb, var(--mf-preset-text, #f1f0ed) 40%, transparent));
  flex-shrink: 0;
  transition: background 0.2s, border-color 0.2s, color 0.2s;
}

/* Active & done states driven by MegaForm renderer */
.mfp.mfp-event-registration-rsvp .mfp-stepper-item.mfp-active .mfp-step-indicator,
.mfp.mfp-event-registration-rsvp .mfp-stepper-item[data-active] .mfp-step-indicator {
  background: var(--mf-primary, #f59e0b);
  border-color: var(--mf-primary, #f59e0b);
  color:var(--mf-preset-on-primary, #0f0f13);
}
.mfp.mfp-event-registration-rsvp .mfp-stepper-item.mfp-done .mfp-step-indicator,
.mfp.mfp-event-registration-rsvp .mfp-stepper-item[data-done] .mfp-step-indicator {
  background: color-mix(in srgb, var(--mf-preset-primary, #f59e0b) 18%, transparent);
  border-color: color-mix(in srgb, var(--mf-preset-primary, #f59e0b) 40%, transparent);
  color: var(--mf-primary, #f59e0b);
}

/* Step info text */
.mfp.mfp-event-registration-rsvp .mfp-step-info {
  display: flex;
  flex-direction: column;
  gap: 2px;
  padding-top: 4px;
}
.mfp.mfp-event-registration-rsvp .step-label {
  font-size: 13px;
  font-weight: 700;
  color: var(--mf-text, #f1f0ed);
  letter-spacing: 0.01em;
}
.mfp.mfp-event-registration-rsvp .step-subtitle {
  font-size: 11px;
  color: var(--mf-muted, color-mix(in srgb, var(--mf-preset-text, #f1f0ed) 40%, transparent));
  letter-spacing: 0.01em;
}

/* Sidebar footer */
.mfp.mfp-event-registration-rsvp .mfp-sidebar-footer {
  margin-top: auto;
  padding-top: 16px;
  border-top: 1px solid var(--mf-border, color-mix(in srgb, var(--mf-preset-text, #ffffff) 7%, transparent));
}
.mfp.mfp-event-registration-rsvp .mfp-sidebar-note {
  font-size: 12px;
  color: var(--mf-muted, color-mix(in srgb, var(--mf-preset-text, #f1f0ed) 38%, transparent));
}
.mfp.mfp-event-registration-rsvp .mfp-sidebar-link {
  color: var(--mf-accent, var(--mf-preset-primary, #f59e0b));
  text-decoration: none;
  font-weight: 600;
}
.mfp.mfp-event-registration-rsvp .mfp-sidebar-link:hover {
  text-decoration: underline;
}

/* ============================================================
   MAIN CONTENT AREA
   ============================================================ */
.mfp.mfp-event-registration-rsvp .mfp-main {
  flex: 1;
  min-width: 0;
  background: var(--mf-bg, var(--mf-preset-bg, #0f0f13));
  display: flex;
  flex-direction: column;
}

/* Mobile stepper (hidden on desktop) */
.mfp.mfp-event-registration-rsvp .mfp-stepper-mobile {
  display: none;
  padding: 20px 24px 0;
  border-bottom: 1px solid var(--mf-border, color-mix(in srgb, var(--mf-preset-text, #ffffff) 7%, transparent));
}
.mfp.mfp-event-registration-rsvp .mfp-stepper-mobile-list {
  list-style: none;
  display: flex;
  gap: 0;
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
}
.mfp.mfp-event-registration-rsvp .mfp-stepper-mobile-item {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 0 16px 16px 0;
  font-size: 12px;
  font-weight: 600;
  color: var(--mf-muted, color-mix(in srgb, var(--mf-preset-text, #f1f0ed) 40%, transparent));
  white-space: nowrap;
  position: relative;
}
.mfp.mfp-event-registration-rsvp .mfp-stepper-mobile-item:not(:last-child)::after {
  content: '';
  position: absolute;
  right: 6px;
  top: 50%;
  transform: translateY(-50%);
  width: 10px;
  height: 1px;
  background: var(--mf-border, color-mix(in srgb, var(--mf-preset-text, #ffffff) 12%, transparent));
}
.mfp.mfp-event-registration-rsvp .mfp-mobile-indicator {
  width: 22px;
  height: 22px;
  border-radius: 50%;
  border: 1px solid var(--mf-border, color-mix(in srgb, var(--mf-preset-text, #ffffff) 15%, transparent));
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 10px;
  font-weight: 700;
  flex-shrink: 0;
}
.mfp.mfp-event-registration-rsvp .mfp-stepper-mobile-item.mfp-active .mfp-mobile-indicator {
  background: var(--mf-primary, #f59e0b);
  border-color: var(--mf-primary, #f59e0b);
  color:var(--mf-preset-on-primary, #0f0f13);
}

/* ===== Page / Step container ===== */
.mfp.mfp-event-registration-rsvp .mfp-page {
  padding: 44px 48px 36px;
  flex: 1;
  display: flex;
  flex-direction: column;
}

/* ===== Section field (step heading) ===== */
.mfp.mfp-event-registration-rsvp .mfp-section-label {
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: var(--mf-accent, var(--mf-preset-primary, #f59e0b));
  margin-bottom: 10px;
  display: block;
}
.mfp.mfp-event-registration-rsvp .mfp-section-heading,
.mfp.mfp-event-registration-rsvp .step-title {
  font-size: clamp(20px, 3vw, 28px);
  font-weight: 800;
  letter-spacing: -0.02em;
  line-height: 1.15;
  color: var(--mf-text, #f1f0ed);
  margin-bottom: 8px;
}
.mfp.mfp-event-registration-rsvp .mfp-section-intro,
.mfp.mfp-event-registration-rsvp .step-intro {
  font-size: 14px;
  line-height: 1.6;
  color: var(--mf-muted, color-mix(in srgb, var(--mf-preset-text, #f1f0ed) 50%, transparent));
  margin-bottom: 32px;
  max-width: 520px;
}

/* ===== Field body spacing ===== */
.mfp.mfp-event-registration-rsvp .mfp-step-body {
  display: flex;
  flex-direction: column;
  gap: 20px;
  flex: 1;
}

/* Two-column row */
.mfp.mfp-event-registration-rsvp .mfp-field-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 16px;
}

/* ===== Labels ===== */
.mfp.mfp-event-registration-rsvp label,
.mfp.mfp-event-registration-rsvp .mfp-label {
  display: block;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--mf-muted, color-mix(in srgb, var(--mf-preset-text, #f1f0ed) 55%, transparent));
  margin-bottom: 7px;
}

/* ===== Inputs, Textareas, Selects ===== */
.mfp.mfp-event-registration-rsvp input[type="text"],
.mfp.mfp-event-registration-rsvp input[type="email"],
.mfp.mfp-event-registration-rsvp input[type="tel"],
.mfp.mfp-event-registration-rsvp input[type="number"],
.mfp.mfp-event-registration-rsvp input[type="date"],
.mfp.mfp-event-registration-rsvp input[type="url"],
.mfp.mfp-event-registration-rsvp textarea,
.mfp.mfp-event-registration-rsvp select {
  width: 100%;
  background: var(--mf-surface, var(--mf-preset-surface, #18181f));
  border: 1px solid var(--mf-border, color-mix(in srgb, var(--mf-preset-text, #ffffff) 10%, transparent));
  border-radius: var(--mf-radius, 8px);
  padding: 11px 14px;
  font-size: 14px;
  font-family: inherit;
  color: var(--mf-text, #f1f0ed);
  transition: border-color 0.18s, box-shadow 0.18s;
  outline: none;
  appearance: none;
  -webkit-appearance: none;
}
.mfp.mfp-event-registration-rsvp input[type="text"]:focus,
.mfp.mfp-event-registration-rsvp input[type="email"]:focus,
.mfp.mfp-event-registration-rsvp input[type="tel"]:focus,
.mfp.mfp-event-registration-rsvp input[type="number"]:focus,
.mfp.mfp-event-registration-rsvp input[type="date"]:focus,
.mfp.mfp-event-registration-rsvp input[type="url"]:focus,
.mfp.mfp-event-registration-rsvp textarea:focus,
.mfp.mfp-event-registration-rsvp select:focus {
  border-color: var(--mf-primary, #f59e0b);
  box-shadow: 0 0 0 3px color-mix(in srgb, var(--mf-preset-primary, #f59e0b) 16%, transparent);
}
.mfp.mfp-event-registration-rsvp input::placeholder,
.mfp.mfp-event-registration-rsvp textarea::placeholder {
  color: var(--mf-muted, color-mix(in srgb, var(--mf-preset-text, #f1f0ed) 25%, transparent));
}
.mfp.mfp-event-registration-rsvp textarea {
  resize: vertical;
  min-height: 80px;
}

/* ===== Hint text ===== */
.mfp.mfp-event-registration-rsvp .mfp-hint,
.mfp.mfp-event-registration-rsvp .mfp-field-hint {
  font-size: 11px;
  color: var(--mf-muted, color-mix(in srgb, var(--mf-preset-text, #f1f0ed) 35%, transparent));
  margin-top: 5px;
  line-height: 1.5;
}

/* ===== Radio & Checkbox groups ===== */
.mfp.mfp-event-registration-rsvp .mfp-radio-group,
.mfp.mfp-event-registration-rsvp .mfp-checkbox-group {
  display: flex;
  flex-direction: column;
  gap: 10px;
}
.mfp.mfp-event-registration-rsvp .mfp-radio-item,
.mfp.mfp-event-registration-rsvp .mfp-checkbox-item {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 11px 14px;
  border-radius: var(--mf-radius, 8px);
  border: 1px solid var(--mf-border, color-mix(in srgb, var(--mf-preset-text, #ffffff) 10%, transparent));
  background: var(--mf-surface, var(--mf-preset-surface, #18181f));
  cursor: pointer;
  transition: border-color 0.18s, background 0.18s;
}
.mfp.mfp-event-registration-rsvp .mfp-radio-item:hover,
.mfp.mfp-event-registration-rsvp .mfp-checkbox-item:hover {
  border-color: color-mix(in srgb, var(--mf-preset-primary, #f59e0b) 35%, transparent);
  background: color-mix(in srgb, var(--mf-preset-primary, #f59e0b) 4%, transparent);
}
.mfp.mfp-event-registration-rsvp .mfp-radio-item input[type="radio"],
.mfp.mfp-event-registration-rsvp .mfp-checkbox-item input[type="checkbox"] {
  width: 16px;
  height: 16px;
  accent-color: var(--mf-primary, #f59e0b);
  flex-shrink: 0;
}
.mfp.mfp-event-registration-rsvp .mfp-radio-item label,
.mfp.mfp-event-registration-rsvp .mfp-checkbox-item label {
  font-size: 13px;
  font-weight: 500;
  color: var(--mf-text, #f1f0ed);
  text-transform: none;
  letter-spacing: 0;
  margin-bottom: 0;
  cursor: pointer;
}

/* Standalone (consent) checkbox */
.mfp.mfp-event-registration-rsvp .mfp-field-checkbox {
  display: flex;
  align-items: flex-start;
  gap: 10px;
  padding: 12px 14px;
  border-radius: var(--mf-radius, 8px);
  border: 1px solid var(--mf-border, color-mix(in srgb, var(--mf-preset-text, #ffffff) 8%, transparent));
  background: transparent;
}
.mfp.mfp-event-registration-rsvp .mfp-field-checkbox input[type="checkbox"] {
  width: 16px;
  height: 16px;
  margin-top: 2px;
  accent-color: var(--mf-primary, #f59e0b);
  flex-shrink: 0;
}
.mfp.mfp-event-registration-rsvp .mfp-field-checkbox label {
  font-size: 13px;
  color: var(--mf-muted, color-mix(in srgb, var(--mf-preset-text, #f1f0ed) 60%, transparent));
  font-weight: 400;
  text-transform: none;
  letter-spacing: 0;
  margin-bottom: 0;
  line-height: 1.5;
}

/* ===== Rating ===== */
.mfp.mfp-event-registration-rsvp .mfp-rating {
  display: flex;
  gap: 8px;
}
.mfp.mfp-event-registration-rsvp .mfp-rating-star {
  font-size: 22px;
  color: var(--mf-border, color-mix(in srgb, var(--mf-preset-text, #ffffff) 15%, transparent));
  cursor: pointer;
  transition: color 0.15s;
}
.mfp.mfp-event-registration-rsvp .mfp-rating-star.mfp-active {
  color: var(--mf-primary, #f59e0b);
}

/* ===== File upload ===== */
.mfp.mfp-event-registration-rsvp .mfp-file-drop {
  border: 1.5px dashed var(--mf-border, color-mix(in srgb, var(--mf-preset-text, #ffffff) 14%, transparent));
  border-radius: var(--mf-radius, 8px);
  padding: 24px;
  text-align: center;
  cursor: pointer;
  transition: border-color 0.18s, background 0.18s;
  background: var(--mf-surface, var(--mf-preset-surface, #18181f));
}
.mfp.mfp-event-registration-rsvp .mfp-file-drop:hover {
  border-color: color-mix(in srgb, var(--mf-preset-primary, #f59e0b) 45%, transparent);
  background: color-mix(in srgb, var(--mf-preset-primary, #f59e0b) 4%, transparent);
}

/* ===== Actions bar ===== */
.mfp.mfp-event-registration-rsvp .mfp-actions {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-top: 32px;
  margin-top: auto;
  border-top: 1px solid var(--mf-border, color-mix(in srgb, var(--mf-preset-text, #ffffff) 7%, transparent));
  gap: 12px;
}

/* ===== Buttons ===== */
.mfp.mfp-event-registration-rsvp .mfp-btn {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  border: none;
  border-radius: var(--mf-radius, 8px);
  padding: 11px 24px;
  font-size: 13px;
  font-weight: 700;
  font-family: inherit;
  letter-spacing: 0.04em;
  cursor: pointer;
  transition: background 0.18s, color 0.18s, opacity 0.18s, transform 0.12s;
  outline: none;
  white-space: nowrap;
}
.mfp.mfp-event-registration-rsvp .mfp-btn:active {
  transform: scale(0.97);
}
.mfp.mfp-event-registration-rsvp .mfp-btn-back {
  background: transparent;
  color: var(--mf-muted, color-mix(in srgb, var(--mf-preset-text, #f1f0ed) 45%, transparent));
  border: 1px solid var(--mf-border, color-mix(in srgb, var(--mf-preset-text, #ffffff) 12%, transparent));
}
.mfp.mfp-event-registration-rsvp .mfp-btn-back:hover {
  color: var(--mf-text, #f1f0ed);
  border-color: color-mix(in srgb, var(--mf-preset-text, #ffffff) 25%, transparent);
}
.mfp.mfp-event-registration-rsvp .mfp-btn-next {
  background: var(--mf-primary, #f59e0b);
  color:var(--mf-preset-on-primary, #0f0f13);
  margin-left: auto;
}
.mfp.mfp-event-registration-rsvp .mfp-btn-next:hover {
  background: var(--mf-preset-primary, #d97706);
}
.mfp.mfp-event-registration-rsvp .mfp-btn-submit {
  background: var(--mf-primary, #f59e0b);
  color:var(--mf-preset-on-primary, #0f0f13);
  padding: 12px 32px;
  font-size: 14px;
  margin-left: auto;
}
.mfp.mfp-event-registration-rsvp .mfp-btn-submit:hover {
  background: var(--mf-preset-primary, #d97706);
}

/* ===== Error states ===== */
.mfp.mfp-event-registration-rsvp .mfp-field-error input,
.mfp.mfp-event-registration-rsvp .mfp-field-error textarea,
.mfp.mfp-event-registration-rsvp .mfp-field-error select {
  border-color: #ef4444;
}
.mfp.mfp-event-registration-rsvp .mfp-error-message {
  font-size: 11px;
  color: #ef4444;
  margin-top: 5px;
  display: block;
}

/* ===== Required asterisk ===== */
.mfp.mfp-event-registration-rsvp .mfp-required::after {
  content: ' *';
  color: var(--mf-accent, var(--mf-preset-primary, #f59e0b));
}

/* ============================================================
   RESPONSIVE
   ============================================================ */
@media (max-width: 720px) {
  .mfp.mfp-event-registration-rsvp .mfp-layout {
    flex-direction: column;
  }
  .mfp.mfp-event-registration-rsvp .mfp-sidebar {
    width: 100%;
    border-right: none;
    border-bottom: 1px solid var(--mf-border, color-mix(in srgb, var(--mf-preset-text, #ffffff) 8%, transparent));
  }
  .mfp.mfp-event-registration-rsvp .mfp-sidebar-inner {
    padding: 24px 20px 20px;
    gap: 16px;
  }
  .mfp.mfp-event-registration-rsvp .mfp-stepper {
    display: none;
  }
  .mfp.mfp-event-registration-rsvp .mfp-sidebar-footer {
    display: none;
  }
  .mfp.mfp-event-registration-rsvp .mfp-stepper-mobile {
    display: block;
  }
  .mfp.mfp-event-registration-rsvp .mfp-page {
    padding: 28px 20px 24px;
  }
  .mfp.mfp-event-registration-rsvp .mfp-field-row {
    grid-template-columns: 1fr;
  }
  .mfp.mfp-event-registration-rsvp .mfp-actions {
    flex-wrap: wrap;
  }
  .mfp.mfp-event-registration-rsvp .mfp-btn-next,
  .mfp.mfp-event-registration-rsvp .mfp-btn-submit {
    width: 100%;
    justify-content: center;
    margin-left: 0;
  }
}

